"""
mkt-original — Genesis chapters 38-40
Run: python3 scripts/zc-original-genesis-38-40.py

Key linguistic coverage:
- Ch 38: wayyered (went down) descent motif (v1); Tamar = palm tree (v6);
  ra be-einei YHWH + divine judgment formula (v7,10); yabam levirate duty verb (v8);
  shakhat — Piel of corruption/ruin (v9); almnut/widow-garments (v14);
  zonah vs. kedeshim distinction (v15,21); eravon/khotem/petil/matteh pledge items (v18);
  haker-na echo of 37:32 (v25); tsadqah mimmeni — Tamar's vindication (v26);
  Perez/parats (break through) = Davidic line (v29)
- Ch 39: sar ha-tabakhim — the slaughterer-captain (v1); YHWH-with-Joseph covenant
  presence formula (v2,21,23); matsliakh/tsalakh prosperity verb (v2); Abrahamic
  blessing radiating outward (v5); Rachel's double beauty formula echoed for Joseph (v6);
  chata le-elohim — sin against God not just Potiphar (v9); beged/garment as evidence
  motif (v12-16); beit ha-sohar circular prison (v20); chesed covenant-loyalty in prison (v21)
- Ch 40: mashqeh/opheh (cupbearer/baker) (v1); pitron/patar — interpretation verb (v8);
  "interpretations belong to God" — the monotheistic claim (v8); yissa Pharaoh et-roshkha
  idiom used for both restoration (v13) and execution (v19); chesed request (v14);
  ganob gunnabti emphatic stolen (v15); ha-bor pit echo of 37:24 (v15);
  lo zakar / wayyishkachehu double forgetting — human vs. divine remembrance (v23)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_ORIGINAL = {
  "38": {
    "1": """<p><strong>wayyēreḏ yĕhûḏāh mēʾēt ʾeḥāyw wayyēṭ ʿaḏ-ʾîš ʿăḏullāmî</strong> — "Judah went down from his brothers." <em>Wayyēreḏ</em> (Qal of <em>yāraḏ</em>, H3381, to go down) — the descent-motif that pervades the Joseph narrative: Joseph was taken down to Egypt (37:25; 39:1), Judah now goes down from his brothers. The chapter is a narrative interruption — placed between Joseph being sold (37:36) and Joseph in Egypt (39:1) — and the temporal marker <em>baʿēt hahîʾ</em> (at that time) links it to the broader Joseph story rather than placing it in a different era. Judah's "going down" and his separation from his brothers contrast with Joseph's parallel descent; both will converge at the covenant level through the Perez/Davidic line (v29).</p>""",
    "2": """<p><strong>wayyarʾ-šām yĕhûḏāh bat-ʾîš kĕnaʿănî ûšĕmô šûaʿ wayyiqqāḥeyhā wayyāḇōʾ ʾēleyhā</strong> — "Judah saw there the daughter of a Canaanite man named Shua, and took her and went in to her." Judah marries a Canaanite woman — the covenant boundary the patriarchs consistently negotiated: Abraham sent for a wife from Aram for Isaac (ch 24), Isaac charged Jacob not to marry a Canaanite (28:1), Esau's Hittite wives were a grief to his parents (26:34-35). Judah's marriage to a Canaanite is not editorially condemned here, but the consequences (Er, Onan, Shelah, and the Tamar crisis) flow from a household built outside the covenant pattern. The verb <em>lāqaḥ</em> (took) — the same taking-verb used for Shechem's assault in 34:2 — occurs without courtship narrative here.</p>""",
    "3": """<p><strong>waṯṯahar waṯṯēled bēn wayyiqrāʾ ʾet-šĕmô ʿēr</strong> — "She conceived and bore a son, and he named him Er." The birth formula — conceive/bear/name — echoes the tribal-birth records of ch 30. <em>ʿĒr</em> (H6147) — the name's etymology is uncertain; it may simply be a family name. The rapid birth sequence (vv3-5, three sons in three verses) compresses the family history to set up the Tamar crisis; the sons matter narratively only in relation to the covenant question of Judah's continuation.</p>""",
    "4": """<p><strong>waṯṯahar ʿôḏ waṯṯēled bēn waṯṯiqrāʾ ʾet-šĕmô ʾônān</strong> — "She conceived again and bore a son and named him Onan." <em>ʾÔnān</em> (H209) — possibly from <em>ʾôn</em> (H205, iniquity/trouble/sorrow) or from the same root as <em>ʾawn</em> (vigor, potency — used in Deut 21:17 for the firstborn's "firstfruits of his strength"). The birth record is minimal; Onan's significance is entirely defined by his act in v9 and the name's subsequent associations.</p>""",
    "5": """<p><strong>waṯṯōsep ʿôḏ waṯṯēled bēn waṯṯiqrāʾ ʾet-šĕmô šēlāh wĕhāyāh biḵzîḇ bĕliddtāh ʾōtô</strong> — "She gave birth to yet another son and named him Shelah; she was at Chezib when she bore him." <em>Šēlāh</em> (H7956) — from an uncertain root; possibly related to <em>šālaḥ</em> (to send) or <em>šelāh</em> (petition). <em>Kĕzîḇ</em> (Chezib, H3580) — a place-name in the Shephelah, possibly the same as Achzib (Josh 15:44; Mic 1:14); its name means "deceitful/lying" (<em>kāzaḇ</em>, H3576) — a narrative irony given the deception that will follow in this chapter.</p>""",
    "6": """<p><strong>wayyiqqaḥ yĕhûḏāh ʾiššāh lĕʿēr bĕḵôrô ûšĕmāh tāmār</strong> — "Judah got a wife for Er his firstborn; her name was Tamar." <em>Tāmār</em> (H8559, palm tree — the date palm, <em>Phoenix dactylifera</em>) — a name connoting beauty, uprightness, and fruitfulness; the same name as David's daughter Tamar (2 Sam 13:1) and Absalom's daughter (2 Sam 14:27). Palm trees were symbols of the righteous in Ps 92:12 ("the righteous shall flourish like a palm tree"). Tamar enters the narrative named but voiceless — she does not speak until v25. The name is her characterization before her character is demonstrated.</p>""",
    "7": """<p><strong>wayhî ʿēr bĕḵôr yĕhûḏāh rāʿ bĕʿênê YHWH wayyĕmîtēhû YHWH</strong> — "But Er, Judah's firstborn, was wicked in the eyes of YHWH; and YHWH put him to death." The formula <em>rāʿ bĕʿênê YHWH</em> (wicked in YHWH's eyes, H7451) is the covenant judgment formula — used for Onan in v10, for the inhabitants of Sodom (13:13), for Israel's kings (1 Kgs 15:26; 16:25; 2 Kgs 21:2). <em>Wayyĕmîtēhû YHWH</em> — "and YHWH put him to death" — a blunt statement of direct divine execution; Er's wickedness is not specified, which keeps the narrative focus on Tamar's subsequent predicament rather than on Er's sin. The divine judgment creates the Levirate obligation.</p>""",
    "8": """<p><strong>wayyōʾmer yĕhûḏāh lĕʾônān bōʾ ʾel-ʾēšet ʾāḥîḵā wĕyabbēm ʾōtāh wĕhāqēm zeraʿ lĕʾāḥîḵā</strong> — "Judah said to Onan, 'Go in to your brother's wife and perform the duty of a brother-in-law for her; raise up offspring for your brother.'" The verb <em>yibbēm</em> (H2992, to perform the Levirate duty, to marry the deceased brother's wife) — the technical term for what Deut 25:5-10 will later codify as <em>yibbum</em> law. The obligation: the surviving brother marries the widow to raise up the <em>zĕraʿ</em> (seed/offspring, H2233) for the dead brother — preserving his name and inheritance in Israel. The Levirate institution is pre-Sinaitic here; Judah invokes it as a known obligation without legal citation. <em>Hāqēm zĕraʿ</em> (raise up seed) — the language of covenant continuation.</p>""",
    "9": """<p><strong>wayyēḏaʿ ʾônān kî lōʾ lô yihyeh hazzāraʿ wĕhāyāh ʾim-bāʾ ʾel-ʾēšet ʾāḥîw wĕšiḥēt ʾarṣāh lĕḇiltî nĕtōn-zĕraʿ lĕʾāḥîw</strong> — "Onan knew the offspring would not be his; so whenever he slept with his brother's wife, he wasted it (<em>šiḥēt</em>) on the ground, so as not to give offspring to his brother." <em>Šiḥēt</em> (Hiphil of <em>šāḥat</em>, H7843, to destroy, corrupt, ruin, waste) — the verb for moral and physical corruption: the golden calf is described with <em>šāḥat</em> (Exod 32:7: "your people have corrupted themselves"); the flood is sent because the earth was <em>šāḥat</em> (6:11-12). Onan does not merely "waste" the seed in a neutral sense — he actively "corrupts" or "ruins" the covenantal seed. The act is an act of destruction directed against his brother's covenant line.</p>""",
    "10": """<p><strong>wayyēraʿ bĕʿênê YHWH ʾăšer ʿāśāh wayyāmēt gam-ʾōtô</strong> — "What he did was wicked in the eyes of YHWH; so he put him to death also." The judgment formula is verbally identical to v7 with the addition of <em>gam-ʾōtô</em> (him also) — emphasizing that both brothers have been executed by YHWH for wickedness. The parallelism of vv7 and 10 creates a narrative pattern that prepares the reader to understand Judah's fear in v11: two sons have already died married to Tamar; Judah calculates (wrongly) that she is the cause rather than their wickedness.</p>""",
    "11": """<p><strong>wayyōʾmer yĕhûḏāh lĕtāmār kallātô šĕḇî ʾalmānāh ḇêt-ʾāḇîḵ ʿaḏ-yiggĕḏal šēlāh ḇĕnî kî ʾāmar pen-yāmût gam-hûʾ kĕʾeḥāyw</strong> — "Judah said to his daughter-in-law Tamar, 'Remain a widow in your father's house until my son Shelah grows up' — for he thought, 'He may die too, just like his brothers.'" <em>ʾAlmānāh</em> (H490, widow, one who is silent/bereft — from <em>ʾālam</em>, to be silent) — the widow in biblical law was among the most vulnerable members of society (Deut 10:18; 24:17-21; Exod 22:22-24). Judah's instruction to Tamar is a legal limbo: she is released from the household but not given Shelah — effectively stranded as a widow without recourse. The narrator's disclosure of Judah's interior motive (v11b) makes clear this is protective pretext, not genuine fulfillment of the Levirate obligation.</p>""",
    "12": """<p><strong>wayyirbu hayyāmîm waṯṯāmāṯ bat-šûaʿ ʾēšet yĕhûḏāh wayyinnāḥem yĕhûḏāh wayyaʿal ʿal-gōzĕzê ṣōʾnô hûʾ wĕhîrāh rēʿēhû hāʿăḏullāmî timnatāh</strong> — "After a long time Judah's wife died. After Judah was comforted, he went up to his sheepshearers at Timnah." <em>Wayyirbu hayyāmîm</em> (the days multiplied/many days passed) — the time-compression formula for waiting. Judah's recovery from grief (<em>wayyinnāḥem</em>, Niphal of <em>nāḥam</em>, H5162, to be comforted, relent) leads directly to the sheep-shearing trip. Sheep shearing (<em>gēzez ṣōʾn</em>) was a festival occasion in the ancient world — associated with feasting and celebratory behavior (cf. 1 Sam 25:4-8 for Nabal's shearing feast). Judah's movement "up" (<em>wayyaʿal</em>) to Timnah while Tamar acts to intercept him is the narrative setup.</p>""",
    "13": """<p><strong>wayyuggad lĕtāmār lēʾmōr hinnēh ḥāmîḵ ʿōleh timnatāh liggōz ṣōʾnô</strong> — "Tamar was told, 'Your father-in-law is on his way up to Timnah to shear his sheep.'" Tamar's being informed by an unnamed messenger (<em>wayyuggad</em> — Hophal: it was told) — the passive form suggests a community network of information. Tamar has been waiting in her father's house without Shelah being given to her; the sheep-shearing occasion presents the opportunity for action. The narrator presents Tamar as a strategic agent responding to information: she has been denied her legal right, and she will act to claim it through the only avenue available.</p>""",
    "14": """<p><strong>waṯṯāsar bigḏê ʾalmĕnûtāh mēʿāleyhā waṯṯĕḵas baṣṣāʿîp waṯṯitʿallāp waṯṯēšeḇ bĕpetaḥ ʿênayim ʾăšer ʿal-dereḵ timnatāh</strong> — "She removed her widow's garments and covered herself with a veil to disguise herself." <em>Bigḏê ʾalmĕnûtāh</em> (widow's garments, from <em>ʾalmānāh</em>) — the clothing of social status; removing them is an act of identity-disguise. <em>Ṣāʿîp</em> (H6809, veil/wrapper) — a large covering garment that obscures identity. <em>Waṯṯitʿallāp</em> (wrapped herself, Hithpael of <em>ʿālap</em>, H5968, to cover/veil oneself) — she actively performs the disguise. <em>Petaḥ ʿênayim</em> (opening of the eyes/Enaim) — possibly a place name meaning "two springs" or "crossroads"; the narrator's note that it was "on the road to Timnah" makes Judah's encounter unavoidable. Her motive is explicitly stated: Shelah had grown up and she had not been given to him.</p>""",
    "15": """<p><strong>wayyirʾehā yĕhûḏāh wayyaḥšĕḇehā lĕzônāh kî kissĕtāh pānêhā</strong> — "Judah saw her and took her for a prostitute (<em>zônāh</em>), for she had covered her face." <em>Zônāh</em> (H2181, harlot/prostitute — Qal participle of <em>zānāh</em>, to commit sexual immorality) — Judah's assumption based on the covered face and the roadside position. Notably, Judah will use a different word in v21 when he instructs Hirah to find her: <em>qĕḏēšāh</em> (H6948, a consecrated/dedicated woman — a cultic term for a woman devoted to a deity, often associated with temple prostitution in ANE practice). Hirah uses the more socially respectable term; the men of the place say there was no <em>qĕḏēšāh</em> there. The distinction between <em>zônāh</em> (ordinary prostitute) and <em>qĕḏēšāh</em> (sacred devotee) reflects two different social-religious categories, and Judah/Hirah's word choice tracks this distinction.</p>""",
    "16": """<p><strong>wayyēṭ ʾēleyhā ʾel-haddereḵ wayyōʾmer hābāh-nāʾ ʾāḇôʾāh ʾēlayin kî lōʾ yāḏaʿ kî kallātô hîʾ</strong> — "He turned aside to her on the road and said, 'Come now, let me come to you' — for he did not know she was his daughter-in-law." The narrator's moral-ironic note (<em>kî lōʾ yāḏaʿ kî kallātô hîʾ</em> — he did not know she was his daughter-in-law) is repeated at v26 for structural emphasis. The unknowing frames Judah's act as unconscious but not innocent — he is propositioning a woman at a roadside, which is itself the moral problem. The subsequent recognition in v26 will require him to acknowledge the double-irony: the woman he violated is more righteous than he is.</p>""",
    "17": """<p><strong>wayyōʾmer ʾānōḵî ʾăšallaḥ gĕḏî-ʿizzîm min-haṣṣōʾn waṯṯōʾmer ʾim-tittēn ʿērāḇôn ʿaḏ šolḥeḵā</strong> — "'I will send a young goat from the flock,' he said. 'Will you give a pledge until you send it?'" <em>Gĕḏî-ʿizzîm</em> (kid/young goat from the goat-flock) — the same animal used for Jacob's deception of Isaac (27:9: goat-kids for the savory dish; 27:16: goat-skins for the arm). <em>ʿĒrāḇôn</em> (H6162, pledge/security deposit) — a commercial-legal term used only here in the OT (vv17,18,20); cognate with the Akkadian <em>erābū</em> and Greek <em>arrabon</em> (Eph 1:14: "the Spirit as the pledge/deposit of our inheritance"). The pledge transforms a transactional encounter into a legally binding arrangement — Judah must reclaim his identifying items or remain legally accountable.</p>""",
    "18": """<p><strong>wayyōʾmer mah-hāʿērāḇôn ʾăšer ʾettēn-lāḵ waṯṯōʾmer ḥôtāmĕḵā ûpĕtîleḵā ûmaṭṭĕḵā ʾăšer bĕyāḏeḵā</strong> — "She answered, 'Your seal, your cord, and your staff in your hand.'" <em>Ḥôtām</em> (H2368, signet seal — a cylinder seal or stamp seal worn on a cord used to authenticate documents and ownership) + <em>pĕtîl</em> (H6616, cord/thread/bracelet — the cord on which the seal hangs) + <em>maṭṭeh</em> (H4294, staff/rod — also the word for a tribal staff/scepter). These three items are Judah's most personally identifying possessions — the equivalent of modern ID documents. Tamar's shrewd choice of pledge items ensures that when the truth is revealed, the evidence is irrefutable. The <em>maṭṭeh</em> (staff) in particular carries the weight of tribal authority: the same word is used for Jacob's tribal staffs (ch 30) and for Moses's staff before Pharaoh.</p>""",
    "19": """<p><strong>waṯṯāqom waṯṯēleḵ waṯṯāsar ṣāʿîpāh mēʿāleyhā waṯṯilḇaš bigḏê ʾalmĕnûtāh</strong> — "She rose and went, removing her veil and putting on her widow's garments again." The reversal is complete: the widow's garments come off for the disguise; they go back on afterward. Tamar's act is not permanent abandonment of her status but a targeted intervention. The garment-change as identity-transformation is a recurring Genesis motif (Joseph's coat of many colors: status; Rebekah's disguising Jacob; Jacob changing clothes for Bethel in 35:2); here it is Tamar who controls the garment-sign.</p>""",
    "20": """<p><strong>wayyišlaḥ yĕhûḏāh ʾet-gĕḏî hāʿizzîm bĕyaḏ rēʿēhû hāʿăḏullāmî lāqaḥat hāʿērāḇôn miyyaḏ hāʾiššāh wĕlōʾ mĕṣāʾāh</strong> — "Judah sent the young goat by his friend the Adullamite, to recover the pledge from the woman, but he did not find her." The recovery attempt uses the intermediary Hirah, possibly because Judah is embarrassed to return in person. The failure to find her sets up the inquiry of v21 — Hirah asks for a <em>qĕḏēšāh</em> (shrine devotee) rather than a <em>zônāh</em> (prostitute), using the more dignified term even in this awkward errand.</p>""",
    "21": """<p><strong>wayyišʾal ʾet-ʾanĕšê mĕqōmāh lēʾmōr ʾayyēh haqqĕḏēšāh hîʾ ʿal-hāʿênayim ʿal-haddāreḵ wayyōʾmĕrû lōʾ-hāyĕtāh ḇāzeh qĕḏēšāh</strong> — "He asked the men of the place, 'Where is the shrine devotee (<em>qĕḏēšāh</em>) who was beside the road at Enaim?' 'There has been no shrine devotee here,' they said." <em>Qĕḏēšāh</em> (H6948, feminine of <em>qāḏôš</em> = holy/set-apart — but in this cultic context designating a woman dedicated to a deity, often associated with fertility cult in Canaanite religion) — Hirah's use of this term rather than <em>zônāh</em> (common prostitute) reflects either social courtesy or his belief that the veiled woman at the roadside was a cultic figure. The men's answer — there has been no <em>qĕḏēšāh</em> here — closes the inquiry. The evidence of the pledge items remains with Tamar.</p>""",
    "22": """<p><strong>wayyāšāḇ ʾel-yĕhûḏāh wayyōʾmer lōʾ mĕṣāʾtîhā wĕgam ʾanĕšê hammāqôm ʾāmĕrû lōʾ-hāyĕtāh ḇāzeh qĕḏēšāh</strong> — "He returned to Judah and reported, 'I didn't find her; and the men of the place said there has been no shrine devotee here.'" Hirah's report closes the pledge-recovery attempt. The word <em>qĕḏēšāh</em> appears twice in vv21-22 — both times by Hirah. The narrator has Judah use <em>zônāh</em> in v15 (his private assumption) and v23 (his frustrated resignation); Hirah consistently uses the more honorable term. The distinction traces the social distance between Judah's private act and its public presentation.</p>""",
    "23": """<p><strong>wayyōʾmer yĕhûḏāh tiqqaḥ-lāh pen niḇûz hinnēh šālaḥtî haggĕḏî hazzeh wĕʾattāh lōʾ mĕṣāʾtāh</strong> — "Judah said, 'Let her keep the pledge, or we will become a laughingstock (<em>lĕḇûz</em>). At least I sent the young goat, but you couldn't find her.'" <em>Lĕḇûz</em> (contempt/laughingstock, H937, from <em>bāzāh</em>, to despise) — Judah's concern is reputation: being known as the man who could not recover his pledge from a prostitute is humiliating. The shame-concern leads him to abandon the search. His words "at least I sent the goat" (<em>šālaḥtî haggĕḏî</em>) acknowledge his contractual obligation without resolving the unredeemed pledge — which remains in Tamar's possession as the evidence she needs.</p>""",
    "24": """<p><strong>wayhî kĕmiššĕlōšāh ḥŏḏāšîm wayyuggad lĕyĕhûḏāh lēʾmōr zāntāh tāmār kallāteḵā wĕgam hinnēh hārāh liznûnîm wayyōʾmer yĕhûḏāh hôṣîʾûhā wĕtissārēp</strong> — "About three months later Judah was told, 'Your daughter-in-law Tamar has played the harlot, and indeed she is pregnant from harlotry.' Judah said, 'Bring her out and burn her!'" The three-month interval allows the pregnancy to be visible and unmistakable. Judah's pronouncement of capital punishment — <em>wĕtissārēp</em> (let her be burned, Niphal of <em>śārap</em>, H8313, to burn) — reflects the penalty for a betrothed woman's sexual infidelity (Lev 21:9 prescribes burning specifically for the daughter of a priest; the broader principle of Deut 22:23-24 prescribes stoning). The irony is that Judah is pronouncing sentence on the very act he initiated — and the sentence reveals his moral double standard: he propositioned a roadside woman but expects his daughter-in-law to maintain sexual fidelity to a levirate promise he has not honored.</p>""",
    "25": """<p><strong>hîʾ mûṣĕʾāh wĕhîʾ šālĕḥāh ʾel-ḥāmîhā lēʾmōr lĕʾîš ʾăšer-ʾēlleh lô ʾānōḵî hārāh waṯṯōʾmer hakkēr-nāʾ lĕmî haḥōtāmet wĕhapĕtîlîm wĕhammaṭṭeh hāʾēlleh</strong> — "As she was brought out, she sent word to her father-in-law: 'I am pregnant by the man whose these are.' And she said, 'Recognize, please, whose seal, cord, and staff these are.'" <em>Hakkēr-nāʾ</em> (recognize/identify, please — Hiphil imperative of <em>nāḵar</em>, H5234, with the particle <em>nāʾ</em>) — this is the precise verbal formula used in 37:32 when Joseph's brothers brought his blood-stained coat to Jacob: <em>hakkēr-nāʾ hakkĕtōnet bĭnĕḵā hîʾ</em> (recognize please, is this your son's coat?). The same words by which Jacob was deceived about Joseph are now spoken to Judah about Tamar — a narrative wordplay linking the two deceptions. Tamar's method of disclosure is indirect — she sends the evidence rather than accusing directly, allowing Judah to make the identification himself.</p>""",
    "26": """<p><strong>wayyakkēr yĕhûḏāh wayyōʾmer ṣāḏĕqāh mimmennî kî-ʿal-kēn lōʾ-nĕtattîhā lĕšēlāh bĕnî wĕlōʾ-yāsap ʿôḏ lĕḏaʿtāh</strong> — "Judah recognized them and said, 'She is more righteous than I (<em>ṣāḏĕqāh mimmennî</em>), for I did not give her to my son Shelah.'" <em>Ṣāḏĕqāh mimmennî</em> — the Qal perfect of <em>ṣāḏaq</em> (H6663, to be righteous, to be in the right) with the comparative preposition <em>min</em>: "she is more in the right than I." This is one of the most direct moral self-indictments in Genesis — a patriarchal figure explicitly acknowledging a woman's superior righteousness. Judah names his own sin of omission: <em>lōʾ nĕtattîhā lĕšēlāh</em> (I did not give her to Shelah). Tamar acted under the pressure of a denied legal right; Judah acted out of self-interest. <em>Wĕlōʾ-yāsap ʿôḏ lĕḏaʿtāh</em> — "he knew her no more" — closing the sexual relationship permanently.</p>""",
    "27": """<p><strong>wayhî bĕʿēt liḏtāh wĕhinnēh tĕʾômîm bĕḇiṭnāh</strong> — "When it was time for her to give birth, behold, twins were in her womb." The exclamatory <em>wĕhinnēh</em> (and behold!) marks the surprise: a twin birth. Twin births in Genesis are theologically significant: Esau and Jacob (25:24) were twins whose birth order was reversed; now Perez and Zerah's reversed emergence will replay the motif. The twin birth signals a covenant-structural event rather than a routine genealogy.</p>""",
    "28": """<p><strong>wayhî bĕliḏtāh wayyittēn-yāḏ waṯṯiqqaḥ hamĕyalleḏet waṯṯiqšōr ʿal-yāḏô šānî lēʾmōr zeh yāṣāʾ riʾšōnāh</strong> — "As she gave birth, one put out his hand; the midwife tied a scarlet thread (<em>šānî</em>) on his wrist and said, 'This one came out first.'" <em>Šānî</em> (H8144, scarlet/crimson) — the scarlet thread designating the firstborn echoes the scarlet thread that Rahab will hang from her window to mark her household for protection (Josh 2:18-21). The scarlet thread as a marking-device that saves and identifies recurs in both texts, though the specific connections are typological rather than direct allusion.</p>""",
    "29": """<p><strong>wayhî kĕmēšîḇ yāḏô wĕhinnēh yāṣāʾ ʾāḥîw waṯṯōʾmer mah-pāraṣtā ʿāleḵā pāreṣ wayyiqrāʾ šĕmô pāreṣ</strong> — "But as he drew back his hand, his brother came out! She said, 'What a breaking-out you have broken! (<em>mah-pāraṣtā ʿāleḵā pāreṣ</em>).' So he was named Perez." <em>Pāreṣ</em> (H6557) from <em>pāraṣ</em> (H6555, to break through, burst out, make a breach) — the birth-reversal naming-speech: the one who seemed to come second burst through first. <em>Pāraṣ</em> is the verb of covenant-overflow: Gen 28:14 (your offspring shall <em>pāraṣ</em> in all directions), 30:30 and 43 (Jacob's flocks <em>pāraṣ</em>). Perez is the direct ancestor of David (Ruth 4:18-22: "Perez begot Hezron... Obed begot Jesse... Jesse begot David") and of the Messiah (Matt 1:3). The birth-reversal of the Tamar narrative — the unexpected supplanter rather than the designated heir — joins the chain of covenant-reversals in Genesis: Abel/Cain, Isaac/Ishmael, Jacob/Esau, Joseph/Reuben, Perez/Zerah.</p>""",
    "30": """<p><strong>wĕʾaḥar yāṣāʾ ʾāḥîw ʾăšer ʿal-yāḏô hašŝānî wayyiqrāʾ šĕmô zāraḥ</strong> — "Then his brother who had the scarlet thread on his wrist came out, and he was named Zerah." <em>Zāraḥ</em> (H2226) — possibly related to <em>zāraḥ</em> (H2224, to rise, shine — used for the sun's rising) or <em>zārak</em> (to sprinkle/scatter). The "shining one" who was marked first but born second — his name may encode the light of the scarlet thread that promised him precedence. Zerah appears in the genealogies (1 Chron 2:4,6) but it is Perez who carries the covenant line to David. The narrative principle is established: the thread of human expectation is not the thread of divine election.</p>"""
  },
  "39": {
    "1": """<p><strong>wĕyôsēp hûraḏ miṣrāymāh wayyiqnēhû potîpar sĕrîs parʿōh sar haṭṭabbāḥîm ʾîš miṣrî miyyaḏ hayišmĕʿēlîm ʾăšer hôrĕḏuhû šāmmāh</strong> — "Joseph had been brought down to Egypt. Potiphar, a court official of Pharaoh, captain of the guard (<em>sar haṭṭabbāḥîm</em>), an Egyptian, bought him from the Ishmaelites." <em>Hûraḏ</em> (Hophal of <em>yāraḏ</em>) — "was brought down" — the passive descent; Joseph is not acting but being acted upon. <em>Sar haṭṭabbāḥîm</em> (captain of the slaughterers/bodyguard, H2876 <em>ṭabbāḥ</em>) — <em>ṭabbāḥ</em> literally means slaughterer/butcher; the title refers to the royal executioner-bodyguard, the officer responsible for the king's personal security and capital punishment. The same title appears in 2 Kgs 25:8 for Nebuchadnezzar's commander who destroys Jerusalem. Joseph has been bought by the man who controls life and death in Pharaoh's household — a narratively significant placement.</p>""",
    "2": """<p><strong>wayhî YHWH ʾet-yôsēp wayhî ʾîš maṣlîaḥ wayhî bĕḇêt ʾăḏōnāyw hammiṣrî</strong> — "YHWH was with Joseph, so he prospered (<em>maṣlîaḥ</em>); and he lived in the house of his Egyptian master." The formula <em>YHWH ʾet-yôsēp</em> (YHWH was with Joseph) — the covenant-presence formula of the patriarchal tradition: "I will be with you" (26:3 to Isaac; 28:15 to Jacob; 31:3 to Jacob). This is the first time in the Joseph narrative that YHWH is named as an active agent; the name had been absent since Jacob's last theophany (35:9-15). <em>Maṣlîaḥ</em> (prospering, Hiphil participle of <em>ṣālaḥ</em>, H6743, to succeed, advance, thrive) — the prosperity is explicitly attributed to divine presence, not to Joseph's native ability. The pattern will repeat at v21 and 23, forming the structural skeleton of the chapter.</p>""",
    "3": """<p><strong>wayyarʾ ʾăḏōnāyw kî YHWH ʾittô wĕḵōl ʾăšer-hûʾ ʿōśeh YHWH maṣlîaḥ bĕyāḏô</strong> — "His master saw that YHWH was with him and that YHWH gave him success in everything he did." The remarkable statement that an Egyptian recognized YHWH's presence in Joseph — a pagan slave-master discerning the divine hand behind his slave's work. This recognition pattern — non-Israelites seeing YHWH's blessing on the covenant people — recurs throughout the Joseph narrative (39:5; 40:15 implies Potiphar's household; 41:38-39 Pharaoh) and foreshadows the Exodus account where Pharaoh and Egypt will be forced to recognize YHWH (Exod 9:16; 14:18). <em>Maṣlîaḥ bĕyāḏô</em> (succeeded in his hand) — "in his hand" frames success as something YHWH places in Joseph's hands.</p>""",
    "4": """<p><strong>wayyimṣāʾ yôsēp ḥēn bĕʿênāyw wayyĕšāret ʾōtô wayyapqidēhû ʿal-bêtô wĕḵol-yeš-lô nātan bĕyāḏô</strong> — "Joseph found favor (<em>ḥēn</em>) in his eyes and became his attendant. He put him in charge of his household and entrusted to his care all that he owned." <em>Māṣāʾ ḥēn</em> (found grace/favor) — the covenant-favor formula (6:8 for Noah; 30:27 for Laban; 32:5 for Jacob before Esau). <em>Mĕšārēt</em> (personal attendant/minister, Piel participle of <em>šārat</em>, H8334, to serve, minister) — the term used for Joshua as Moses's attendant (Exod 24:13; Josh 1:1), for temple service, and for angelic service (Ps 103:21). Joseph's role in Potiphar's household mirrors the role of a Joseph-type in every subsequent context: elevated to administrator, entrusted with total care.</p>""",
    "5": """<p><strong>wayhî mēʾāz hipqîḏ ʾōtô bĕḇêtô wĕʿal kol-ʾăšer yĕš-lô wayyĕḇāreḵ YHWH ʾet-bêt hammiṣrî biglal yôsēp</strong> — "From the time he put him in charge of his household and all he owned, YHWH blessed the Egyptian's household for Joseph's sake." The blessing-formula <em>wayyĕḇāreḵ YHWH ʾet-bêt hammiṣrî biglal yôsēp</em> is the Abrahamic covenant promise extending outward through Joseph: "I will bless those who bless you" (12:3). The Egyptian household is blessed not because of anything Egyptian, but through the covenant-bearer in their midst. The same pattern will appear in 39:23 (prison), 41:37-45 (all of Egypt), and later in Daniel, Esther, and Ezra — the covenant people in exile blessing the surrounding nations.</p>""",
    "6": """<p><strong>wĕyôsēp hāyāh yĕpeh-tōʾar wîpeh marʾeh</strong> — "Now Joseph was well-built and handsome (<em>yĕpeh-tōʾar wîpeh marʾeh</em>)." The double beauty formula — <em>yĕpeh-tōʾar</em> (beautiful of form/shape) + <em>yĕpeh marʾeh</em> (beautiful of appearance/face) — is identical to the description of his mother Rachel in 29:17 (<em>yĕpat-tōʾar wîpat marʾeh</em>). Joseph inherits Rachel's beauty formula — a narrative signal connecting mother and son that the reader of the prior chapters will recognize. The same superlative double appears for Esther (Est 2:7) and David is described with a similar formula (1 Sam 16:12). The beauty serves the narrative: Potiphar's wife will see and desire (v7), echoing the pattern of the predatory gaze (Shechem/Dinah in 34:2).</p>""",
    "7": """<p><strong>wayhî ʾaḥar haddĕḇārîm hāʾēlleh waṯṯiśśāʾ ʾēšet-ʾăḏōnāyw ʾet-ʿênêhā ʾel-yôsēp waṯṯōʾmer šiḵḇāh ʿimmî</strong> — "After these things his master's wife cast her eyes on Joseph and said, 'Lie with me!'" <em>Waṯṯiśśāʾ... ʾet-ʿênêhā</em> (she lifted her eyes) — the predatory gaze construction used for Shechem (34:2: "he saw her"), for Lot's wife (19:26), and for Laban (29:1: Jacob lifted his feet after looking). Here it is the woman who is the desiring agent. The invitation <em>šiḵḇāh ʿimmî</em> (lie with me) is bare, direct, and without the rhetorical setup Potiphar's wife will provide in v17 when she accuses Joseph — there the same words become a false accusation.</p>""",
    "8": """<p><strong>wayĕmāʾēn wayyōʾmer ʾel-ʾēšet ʾăḏōnāyw hēn ʾăḏōnî lōʾ-yāḏaʿ ʾittî mah-babbāyit wĕḵōl ʾăšer-yeš-lô nātan bĕyāḏî</strong> — "But he refused. He said to his master's wife, 'My master does not concern himself with anything in the house; everything he owns he has put in my care.'" Joseph's refusal is grounded in the covenant-faithfulness to Potiphar: the trust placed in him. <em>Wayĕmāʾēn</em> (he refused, Piel of <em>māʾen</em>, H3985) — a strong refusal-verb; used for Moses's refusal to be called Pharaoh's son (Heb 11:24), for Israel's refusal to be comforted (Gen 37:35), and for Pharaoh's refusal to let Israel go (Exod 7:14). Joseph's refusal of Potiphar's wife anticipates these later refusals-in-faith.</p>""",
    "9": """<p><strong>ʾêḵāh ʾeʿĕśeh hārāʿāh hag-gĕḏōlāh hazzōʾt wĕḥāṭāʾtî lēʾlōhîm</strong> — "How could I do this great evil and sin against God?" <em>Wĕḥāṭāʾtî lēʾlōhîm</em> (and sin against God, H430) — Joseph grounds the refusal not only in loyalty to Potiphar (<em>rāʿāh lēʾḏōnî</em>, evil against my master, v8) but in theological ethics: sin against God. The word <em>ḥāṭāʾ</em> (H2398, to sin, to miss the mark, to commit a moral offense) — the standard OT term for moral and religious transgression. Joseph's theological framing of sexual ethics is remarkable in the narrative context: he identifies the sin as directed against God, not merely as a breach of social loyalty. This anticipates the covenant ethic of the Decalogue (Exod 20:14) and psalmic wisdom (Ps 51:4: "against you, you only, have I sinned").</p>""",
    "10": """<p><strong>wayhî kĕḏabbĕrāh ʾel-yôsēp yôm yôm wĕlōʾ-šāmaʿ ʾēleyhā liškōḇ ʾeṣlāh lihyôt ʿimmāh</strong> — "She spoke to Joseph day after day; he refused to lie beside her or be with her." The phrase <em>yôm yôm</em> (day after day, day by day) — the persistence of the temptation. The narrative's insistence on Joseph's sustained refusal over repeated solicitation is theologically significant: his virtue is not a single act of will but a sustained pattern. <em>Wĕlōʾ-šāmaʿ ʾēleyhā</em> (he did not listen to her) — using the hearing-verb <em>šāmaʿ</em> for moral compliance: to "hear" someone was to obey; his refusal to "hear" her is his moral consistency.</p>""",
    "11": """<p><strong>wayhî kĕhayyôm hazzeh wayyāḇōʾ habbāytāh laʿăśôt mĕlaʾḵtô wĕʾên ʾîš mēʾanĕšê habbayit šām babbāyit</strong> — "One day he went into the house to attend to his duties, and none of the household servants was inside." The narrative detail — no household servants present — is the circumstantial condition that makes Potiphar's wife's entrapment possible. <em>Laʿăśôt mĕlaʾḵtô</em> (to do his work/task) — Joseph is present for professional duty, not for personal desire. The absence of witnesses is the condition for both the assault and the false accusation that follows; there is no corroborating testimony for either party.</p>""",
    "12": """<p><strong>waṯṯiṯpĕśēhû bĕḇiḡḏô lēʾmōr šiḵḇāh ʿimmî wayyaʿăzōḇ biḡḏô bĕyāḏāh wayyānos wayyēṣēʾ haḥûṣāh</strong> — "She grabbed him by his garment (<em>ḇegeḏ</em>) saying 'Lie with me!' But he left his garment in her hand and fled outside." <em>Begeḏ</em> (H899, garment/cloak) — garments in the Joseph narrative are consistently the material sign of identity, status, and evidence: the coat of many colors (37:3,23,31-32: torn and blood-stained as evidence of death), this garment (39:12-16: as evidence of assault), the royal robes of ch 41 (as evidence of elevation), the five changes of clothes for Benjamin (45:22). Joseph leaves his <em>begeḏ</em> as involuntary evidence — the same mechanism by which his coat was used against him in ch 37. <em>Wayyānos</em> (he fled, from <em>nûs</em>, H5127) — the same verb used in Exod 14:25 for the Egyptians fleeing from Israel and in Joseph's blessing (49:21).</p>""",
    "13": """<p><strong>wayhî kirʾōtāh kî-ʿāzaḇ biḡḏô bĕyāḏāh wayyānos haḥûṣāh</strong> — "When she saw that he had left his garment in her hand and fled outside…" The <em>begeḏ</em> becomes the evidence-item for her false accusation. The same garment that Potiphar's wife grabbed as an instrument of seduction is now transformed into an instrument of accusation. The repeated mention of the garment (vv12,13,15,16,18) shows that the narrator wants the reader to track the garment's transformation from seduction-tool to false-evidence.</p>""",
    "14": """<p><strong>waṯṯiqrāʾ lĕʾanĕšê ḇêtāh waṯṯōʾmer lāhem lēʾmōr rĕʾû hēḇîʾ lānû ʾîš ʿiḇrî lĕṣaḥeq ḇānû</strong> — "She called to the men of the household and said, 'See, he brought us a Hebrew (<em>ʿiḇrî</em>) to mock us!'" <em>ʿIḇrî</em> (Hebrew, H5680, from <em>ʿēḇer</em>, H5677 — one from beyond/the other side; the ethnic designation for Israelites used by outsiders) — Potiphar's wife uses the ethnic label as a derogatory marker: "this Hebrew" (<em>ʾîš ʿiḇrî</em>) dehumanizes Joseph by his foreignness. In the Joseph narrative, "Hebrew" is always used by Egyptians about Joseph (39:14,17; 41:12) or by Joseph self-identifying to the cupbearer (40:15). The ethnic insult functions to deflect suspicion from herself by making Joseph's alleged aggression a racial as well as personal offense.</p>""",
    "15": """<p><strong>wayhî kĕhārîmî qôlî wāʾeqrāʾ wayyaʿăzōḇ beḡḏô ʾeṣlî wayyānos haḥûṣāh</strong> — "When I raised my voice and screamed, he left his garment beside me and ran outside." The false accusation inverts the narrative: her grabbing becomes his fleeing; his leaving the garment (which she grabbed) becomes evidence of his assault. The <em>begeḏ</em> left "beside me" (<em>ʾeṣlî</em>) is the linchpin of her case — physical evidence she controls and can present to Potiphar. The identical language between her accusation and the narrator's account (vv12-13) allows the reader to track what actually happened versus what she claims.</p>""",
    "16": """<p><strong>waṯṯannah beḡḏô ʾeṣlāh ʿaḏ-bôʾ ʾăḏōnāyw ʾel-bêtô</strong> — "She kept his garment beside her until his master came home." The preserved garment is deliberate: it functions as exhibit A. The time gap — keeping it until Potiphar returns — suggests she is preparing her narrative rather than acting in immediate outrage. The narrator notes this without comment; the detail itself indicts her.</p>""",
    "17": """<p><strong>waṯṯĕḏabbēr ʾēlāyw kaddĕḇārîm hāʾēlleh lēʾmōr bāʾ-ʾēlay hāʿeḇeḏ hāʿiḇrî ʾăšer-hēḇēʾtā lānû lĕṣaḥeq bî</strong> — "She told him this same story: 'The Hebrew slave (<em>hāʿeḇeḏ hāʿiḇrî</em>) you brought us came to me to mock me.'" Now the double label is applied: <em>hāʿeḇeḏ hāʿiḇrî</em> (the Hebrew slave) — both his slave-status and his ethnicity are deployed as the accusation's framing. Before the servants (v14) she said "a Hebrew man"; before Potiphar she says "the Hebrew slave" — the second formulation adds the social-status insult to the ethnic one. The phrase implicates Potiphar himself ("you brought us") — she holds him partially responsible for bringing this danger into their house.</p>""",
    "18": """<p><strong>wayhî kĕhārîmî qôlî wāʾeqrāʾ wayyaʿăzōḇ beḡḏô ʾeṣlî wayyānos haḥûṣāh</strong> — "When I raised my voice and screamed, he left his garment beside me and ran outside." The verbatim repetition of v15 is the narrator's device for emphasizing the lie's consistency — she tells the same story twice to make it stick. The repetition also underscores what the reader already knows to be false, creating the tension between testimony and truth that will only be resolved by God's providence (41:1).</p>""",
    "19": """<p><strong>wayhî kišmōaʿ ʾăḏōnāyw ʾet-diḇrê ʾištô ʾăšer dibbĕrāh ʾēlāyw lēʾmōr kaddĕḇārîm hāʾēlleh ʿāśāh lî ʿaḇdeḵā wayyiḥar ʾappô</strong> — "When his master heard his wife's story, his anger burned." <em>Wayyiḥar ʾappô</em> (his anger burned, H2734 + H639 — literally "his nose burned hot") — the standard idiom for intense anger; <em>ʾap</em> (nose) because the nostrils flare with rage. The narrator does not say Potiphar believed his wife; only that his anger burned. The subsequent punishment (imprisonment rather than execution — the expected penalty for rape of a master's wife) may suggest Potiphar's partial skepticism: he punishes but does not execute, possibly because he knows Joseph's character.</p>""",
    "20": """<p><strong>wayyiqqaḥ ʾăḏōnê yôsēp ʾōtô wayyittĕnēhû ʾel-bêt hassohar mĕqôm ʾăšer-ʾăsûrê hammelek ʾăsûrîm</strong> — "Joseph's master put him in the prison (<em>bêt hassohar</em>), the place where the king's prisoners were held." <em>Bêt hassohar</em> (house of the sohar, H5470) — <em>sohar</em> appears to be an Egyptian loanword or a Hebrew word for a circular/round place (<em>sāḥar</em>, H5437, to go around); possibly referring to an Egyptian-style round or pit-prison. The location — "where the king's prisoners were confined" — is a royal facility, higher-status than a common jail. This placement is significant: Joseph will meet Pharaoh's own officials (the cupbearer and baker in ch 40) precisely because they are imprisoned in the same royal facility. What appears to be a punishment is actually a providential placement.</p>""",
    "21": """<p><strong>wayhî YHWH ʾet-yôsēp wayyēṭ ʾēlāyw ḥāseḏ wayyittēn ḥinnô bĕʿênê śar bêt-hassohar</strong> — "But YHWH was with Joseph and showed him <em>ḥeseḏ</em> (covenant-loyalty/lovingkindness) and gave him favor (<em>ḥēn</em>) in the eyes of the prison warden." The renewal of the <em>YHWH ʾet-yôsēp</em> formula (from v2) at the transition to prison is the structural signal: the divine presence does not depend on circumstance. <em>Ḥeseḏ</em> (H2617, covenant-loyalty, steadfast love, lovingkindness) — the most theologically dense word in the OT's relational vocabulary; it carries the weight of covenant obligation, faithfulness to relationship, and active benevolence. YHWH's <em>ḥeseḏ</em> is the foundation of the psalmic covenant vocabulary (Ps 118:1; 136:1-26; Lam 3:22-23). Joseph in prison receives the same covenant-love that the patriarchs received in freedom.</p>""",
    "22": """<p><strong>wayyittēn śar bêt-hassohar bĕyaḏ-yôsēp ʾēt kol-hāʾăsûrîm ʾăšer bĕḇêt-hassohar wĕʾēt kol-ʾăšer ʿōśîm šām hûʾ hāyāh ʿōśeh</strong> — "The warden put Joseph in charge of all the prisoners and everything done there." The prison chapter exactly mirrors the Potiphar chapter: in vv2-6 Potiphar saw YHWH was with Joseph, entrusted everything to his care, and was unconcerned about anything; in vv21-23 the warden sees YHWH is with Joseph, entrusts everything to his care, and is unconcerned about anything. The mirror structure establishes a pattern: wherever Joseph is placed, YHWH turns it into a place of authority-delegation. The structural repetition is the theological argument.</p>""",
    "23": """<p><strong>ʾên śar bêt-hassohar rōʾeh ʾet-kol-mĕʾûmāh bĕyāḏô baʾăšer YHWH ʾittô waʾăšer-hûʾ ʿōśeh YHWH maṣlîaḥ</strong> — "The warden paid no attention to anything in Joseph's care, because YHWH was with him; and whatever he did YHWH made it prosper (<em>maṣlîaḥ</em>)." The closing formula mirrors the opening of the chapter (v2: "YHWH was with Joseph and he was a <em>maṣlîaḥ</em> man") — <em>maṣlîaḥ</em> (Hiphil of <em>ṣālaḥ</em>) bookends the chapter. The chapter structure is: YHWH is with Joseph (v2) → Potiphar entrusts everything (vv3-6) → temptation and accusation (vv7-19) → prison (v20) → YHWH is with Joseph (v21) → warden entrusts everything (vv22-23). The covenant presence is the constant; the circumstances are the variable.</p>"""
  },
  "40": {
    "1": """<p><strong>wayhî ʾaḥar haddĕḇārîm hāʾēlleh ḥāṭĕʾû mašqēh melek-miṣrayim wĕhāʾōpeh laʾăḏōnêhem lĕmelek miṣrāyim</strong> — "Some time later, the cupbearer and the baker of the king of Egypt offended their master." <em>Mašqeh</em> (H4945, cupbearer/butler — one who causes to drink, from <em>šāqāh</em>, H8248, to give drink) — the royal cupbearer was a high-ranking official in the ancient Near East, responsible for tasting and serving the king's wine and often serving as personal confidant (Nehemiah was a cupbearer to the Persian king, Neh 1:11). <em>ʾōpeh</em> (H644, baker, Qal participle of <em>ʾāpāh</em>, to bake) — another high-ranking court official. Both men's offense (<em>ḥāṭĕʾû</em>, from <em>ḥāṭāʾ</em>, to sin/offend) is unspecified — the narrative interest is in their dreams, not their crimes.</p>""",
    "2": """<p><strong>wayyiqṣōp parʿōh ʿal šĕnê sārîsāyw ʿal śar hammašqîm wĕʿal śar hāʾōpîm</strong> — "Pharaoh was angry (<em>wayyiqṣōp</em>) with his two officials, the chief cupbearer and the chief baker." <em>Qāṣap</em> (H7107, to be furious, to be angry) — a strong anger-verb; the same word used for Moses's anger at the Israelites returning from battle (Num 31:14) and for God's anger in prophetic contexts (Isa 8:21; 47:6). The elevating of "chief" (<em>śar</em>) for both officials distinguishes them from lesser staff — these are senior court officers, which explains both their access to the royal prison facility and their dream's connection to Pharaoh's fate.</p>""",
    "3": """<p><strong>wayyittēn ʾōtām bĕmiš̀mar bêt śar haṭṭabbāḥîm ʾel-bêt hassohar mĕqôm ʾăšer yôsēp āsûr šām</strong> — "He put them in custody in the house of the captain of the guard, in the same prison where Joseph was confined." The geographical identification — the same prison where Joseph is (<em>mĕqôm ʾăšer yôsēp āsûr šām</em>) — is the providential coincidence of the narrative. The captain of the guard's facility is Potiphar's household facility: this is the same man who imprisoned Joseph (39:1). The narrative loop closes: the man who imprisoned Joseph now houses the two officials who will connect Joseph to Pharaoh.</p>""",
    "4": """<p><strong>wayyipqōḏ śar haṭṭabbāḥîm ʾet-yôsēp ʾittām wayyĕšāret ʾōtām wayyihyû yāmîm bĕmišmar</strong> — "The captain of the guard assigned them to Joseph, and he attended them (<em>wayyĕšāret</em>). They remained in custody for some time." <em>Wayyĕšāret</em> (Piel of <em>šārat</em>, H8334, to serve/minister) — the same term used for Joseph's service to Potiphar (39:4). The assignment is casual from the captain's perspective; from the narrative's perspective it is the mechanism by which Joseph encounters the officials. <em>Yāmîm</em> (days/a period of time) — the indefinite duration in custody sets up the night of the dreams.</p>""",
    "5": """<p><strong>wayyaḥălĕmû ḥălôm šĕnêhem ʾîš ḥălōmô bĕlaylāh ʾeḥāḏ ʾîš kĕpitrôn ḥălōmô hammašqeh wĕhāʾōpeh ʾăšer lĕmelek miṣrāyim ʾăšer ʾăsûrîm bĕḇêt hassohar</strong> — "Each of the two men — the cupbearer and the baker of the king of Egypt — had a dream the same night, each with its own interpretation (<em>pitrôn</em>)." <em>Pitrôn</em> (H6623, interpretation/explanation, from <em>pātar</em>, H6622, to interpret/solve) — the interpretation is described as inherent to the dream: each dream has its own <em>pitrôn</em>. The word <em>pātar</em> appears only in the Joseph narrative in the OT; it is possibly an Egyptian loanword for the professional dream-interpretation (<em>ptr</em> in Egyptian). Joseph will claim in v8 that <em>pitrōnîm</em> belong to God — using the very professional vocabulary to deny the professional claim.</p>""",
    "6": """<p><strong>wayyāḇōʾ ʾălêhem yôsēp babbōqer wayyarʾ ʾōtām wĕhinnām zōʿăpîm</strong> — "When Joseph came to them in the morning, he saw they were dejected (<em>zōʿăpîm</em>)." <em>Zōʿăpîm</em> (H2196, Qal participle plural of <em>zāʿap</em>, to be troubled/gloomy/sad) — this word for downcast appearance occurs only here in the Pentateuch; it describes a visible emotional state that Joseph reads on their faces. Joseph's attentiveness to the emotional state of those in his care — asking "why do you look so sad?" (v7) rather than proceeding to his duties — is a mark of the pastoral-administrator figure he has become.</p>""",
    "7": """<p><strong>wayyišʾal ʾet-sārîsê parʿōh ʾăšer ʾittô bĕmiš̀mar bêt ʾăḏōnāyw lēʾmōr maddûaʿ pĕnêḵem rāʿîm hayyôm</strong> — "He asked Pharaoh's officials who were in custody with him, 'Why are your faces downcast (<em>rāʿîm</em>) today?'" <em>Pĕnêḵem rāʿîm</em> (your faces are evil/downcast) — <em>raʿ</em> (H7451, bad/evil/sad) applied to facial appearance; the same word used for Er's wickedness (38:7) and later for the seven gaunt cows of Pharaoh's dream (41:3). Joseph's direct question rather than passive observation is a narrative signal: he is actively engaging with those in his care. This pastoral attentiveness is the condition for the dream-disclosure that will follow.</p>""",
    "8": """<p><strong>wayyōʾmĕrû ʾēlāyw ḥălôm ḥālamnu ûpōtēr ʾên ʾōtô wayyōʾmer ʾălêhem yôsēp hălôʾ lēʾlōhîm pitrōnîm sappĕrû-nāʾ lî</strong> — "They answered, 'We have had dreams and there is no one to interpret them.' Joseph said, 'Do not interpretations belong to God (<em>hălôʾ lēʾlōhîm pitrōnîm</em>)? Tell me your dreams.'" The theological claim is the interpretive key to the entire dream-sequence. <em>Hălôʾ lēʾlōhîm pitrōnîm</em> — the rhetorical question expects "yes" — interpretations belong to God, not to professional dream-interpreters. Joseph refuses the position of wise-man-for-hire (which Egyptian dream-interpretation was) and instead attributes interpretation to divine disclosure. This places him in the prophetic tradition rather than the mantic tradition: he does not decode symbols by professional expertise but receives revelation. The claim is borne out when God gives the interpretation (vv12-19 show Joseph receiving, not calculating, the meaning).</p>""",
    "9": """<p><strong>wayyĕsappēr śar-hammašqîm ʾet-ḥălōmô lĕyôsēp wayyōʾmer lô baḥălōmî wĕhinnēh-gefen lĕpānāy</strong> — "So the chief cupbearer told Joseph his dream: 'In my dream I saw a vine in front of me.'" The vine (<em>gefen</em>, H1612) — a central symbol of covenant blessing in the OT (Ps 128:3: "your wife like a fruitful vine"; Isa 5:1-7: YHWH's vineyard as Israel; Mic 4:4: "each man under his vine and fig tree"). In the cupbearer's dream, the vine is the source of Pharaoh's cup — the productive symbol that defines the cupbearer's entire vocational existence. The dream's simplicity — vine, branches, grapes, cup, Pharaoh's hand — maps directly onto the cupbearer's daily professional actions.</p>""",
    "10": """<p><strong>ûḇaggepen šĕlōšāh śārîgîm wĕhîʾ kĕporāḥat ʿālĕtāh niṣṭāh hēḇîʾû ʾašĕkĕlōtêyhā ʿănāḇîm</strong> — "On the vine were three branches. As it budded, it blossomed, and its clusters ripened into grapes." The three branches (<em>šĕlōšāh śārîgîm</em>) develop in accelerated sequence — bud, blossom, ripe grapes — suggesting a compressed time-vision rather than ordinary agricultural time. The acceleration from bud to harvest in the dream-vision is the narrative signal that an interpretation is required: ordinary vines do not compress agricultural seasons into a single moment. <em>ʿĂnāḇîm</em> (grapes, H6025) — the specific fruit that will be expressed into Pharaoh's cup.</p>""",
    "11": """<p><strong>wĕkôs parʿōh bĕyāḏî wāʾeqqaḥ ʾet-hāʿănāḇîm wāʾeqōṣ ʾōtām ʾel-kôs parʿōh wāʾettēn ʾet-hakôs ʿal-kap parʿōh</strong> — "Pharaoh's cup was in my hand, and I took the grapes, squeezed them into Pharaoh's cup and put the cup in Pharaoh's hand." The dream recreates the cupbearer's professional function: take grapes, squeeze into cup, deliver to Pharaoh. The cup (<em>kôs</em>, H3563) is the central object of the cupbearer's ministry — it appears three times in this single verse. The restoration-dream has the cupbearer doing exactly what he is supposed to do. Joseph's interpretation (v13) will confirm that doing one's proper function in Pharaoh's presence = restoration to honor.</p>""",
    "12": """<p><strong>wayyōʾmer lô yôsēp zeh pitrōnô šĕlōšet haśśārîgîm šĕlōšet yāmîm hēm</strong> — "Joseph said, 'This is its interpretation: the three branches are three days.'" <em>Zeh pitrōnô</em> (this is its interpretation) — the confident, direct formula for dream interpretation; no hedging, no conditional language. <em>Šĕlōšet yāmîm hēm</em> (they are three days) — the symbol-to-referent identification: branches = days. The number three recurs in both dreams (three branches, three baskets) and will be fulfilled on the third day (v20). The "third day" as the day of fulfillment is a temporal marker that carries covenantal weight throughout the OT (Gen 22:4; Exod 19:11,16; Hos 6:2).</p>""",
    "13": """<p><strong>bĕʿôḏ šĕlōšet yāmîm yiśśāʾ parʿōh ʾet-rōʾšĕḵā ûhăšîḇĕḵā ʿal-kannāteḵā wĕnātattā kôs-parʿōh bĕyāḏô</strong> — "Within three days Pharaoh will lift up your head (<em>yiśśāʾ... ʾet-rōʾšĕḵā</em>) and restore you to your position." <em>Yiśśāʾ ʾet-rōʾšĕḵā</em> (he will lift your head) — a Hebrew idiom for restoration to honor and position. The same idiom will be used in v19 for the baker's execution — "he will lift off your head" — but with a different verb and referent. The wordplay is dark: both men receive "head-lifting" from Pharaoh, but the type differs entirely. Joseph's positive interpretation comes first, establishing the idiom before inverting it.</p>""",
    "14": """<p><strong>kî ʾim-zĕḵartanî ʾittĕḵā kaʾăšer yîṭaḇ lāḵ wĕʿāśîtā-nāʾ ʿimmî ḥeseḏ wĕhizkarttanî ʾel-parʿōh wĕhôṣēʾtanî min-habbayit hazzeh</strong> — "But remember me when it goes well with you; show me <em>ḥeseḏ</em> and mention me to Pharaoh, and get me out of this house." Joseph's request uses the covenant-vocabulary: <em>zakar</em> (H2142, to remember — the covenant-memory verb; God "remembered" Noah, Rachel, Abraham for Lot) and <em>ḥeseḏ</em> (H2617, covenant-loyalty/lovingkindness). He asks the cupbearer to show the same covenantal faithfulness that YHWH shows to Joseph. <em>Hazzeh</em> (this house) — Joseph refers to the prison as a "house" (<em>bêt hassohar</em>, house of the prison, 39:20) — the same vocabulary as Potiphar's house where YHWH blessed everything. The irony: both houses have become sites of YHWH's presence with Joseph.</p>""",
    "15": """<p><strong>kî-gunnōḇ gunnabbatî mēʾereṣ hāʿiḇrîm wĕgam-pōh lōʾ-ʿāśîtî mĕʾûmāh kî-śāmû ʾōtî babbôr</strong> — "I was indeed stolen (<em>gunnōḇ gunnabbatî</em>) from the land of the Hebrews, and even here I have done nothing to deserve being put in a pit (<em>babbôr</em>)." <em>Gunnōḇ gunnabbatî</em> — the Qal infinitive absolute + perfect (emphatic form): "I was truly stolen/kidnapped." <em>Gānab</em> (H1589, to steal, kidnap) — the Eighth Commandment verb (Exod 20:15). Joseph's self-description as a stolen person positions his slavery as a crime against himself, not a legitimate status. <em>ʾEreṣ hāʿiḇrîm</em> (land of the Hebrews) — the first use of this phrase, identifying Canaan from the perspective of the Egyptian diaspora. <em>Babbôr</em> (the pit/cistern/dungeon, H953) — the same word used for the pit Joseph's brothers threw him into in 37:24 (<em>habôr rēq</em>, the empty pit); the Egyptian prison is linguistically identified with the original abandonment. Joseph's narrative of descent is a single story: pit → Potiphar's prison → pit again.</p>""",
    "16": """<p><strong>wayyarʾ śar-hāʾōpîm kî ṭôḇ pātar wayyōʾmer ʾel-yôsēp ʾap-ʾănî baḥălōmî wĕhinnēh šĕlōšāh sallê ḥōrî ʿal-rōʾšî</strong> — "When the chief baker saw that Joseph had given a favorable interpretation (<em>pātar</em>), he said: 'I also had a dream.'" The baker's disclosure is motivated by the cupbearer's positive outcome — he wants the same. <em>Pātar</em> (H6622, to interpret dreams) — the baker sees that Joseph's interpretation was "good" (<em>ṭôḇ</em>) and decides to share his own dream. The narrative irony is that the baker's eagerness leads him to hear a death sentence. The basket imagery — three baskets on his head — contrasts with the cupbearer's active hand-delivering image; the baker is passive, and the birds eat the food before it reaches Pharaoh.</p>""",
    "17": """<p><strong>ûḇassal hāʿelyôn mikkōl maʾăḵal parʿōh maʿăśēh ʾōpeh wĕhāʿôp ʾōḵēl ʾōtām min-hassal mēʿal rōʾšî</strong> — "In the top basket were all kinds of baked goods for Pharaoh, but the birds were eating them from the basket on my head." The birds eating the food before it reaches Pharaoh is the key detail: in the cupbearer's dream the cup reaches Pharaoh's hand; in the baker's dream the food never reaches Pharaoh at all — intercepted by birds. The baker cannot fulfill his professional function (providing food to Pharaoh) even in his own dream — the dream itself signals a disruption of service that the waking interpretation confirms.</p>""",
    "18": """<p><strong>wayyaʿan yôsēp wayyōʾmer zeh pitrōnô šĕlōšet hasisallîm šĕlōšet yāmîm hēm</strong> — "Joseph answered, 'This is its interpretation: the three baskets are three days.'" The identical interpretation formula — <em>zeh pitrōnô... šĕlōšet yāmîm hēm</em> — as in v12 signals that the pattern is the same. Both dreams involve three items = three days. The parallelism confirms the method of Joseph's interpretation and sets up the contrast: same formula, opposite outcome.</p>""",
    "19": """<p><strong>bĕʿôḏ šĕlōšet yāmîm yiśśāʾ parʿōh ʾet-rōʾšĕḵā mēʿāleḵā wĕtālāh ʾôtĕḵā ʿal-ʿēṣ wĕʾāḵal hāʿôp ʾet-bĕśārĕḵā mēʿāleḵā</strong> — "Within three days Pharaoh will lift off your head (<em>yiśśāʾ... mēʿāleḵā</em>) and impale you on a pole, and the birds will eat your flesh." The same idiom — <em>yiśśāʾ ʾet-rōʾšĕḵā</em> (lift your head) — is used for both interpretation (v13), but here with the preposition <em>mēʿāleḵā</em> (from off you/away from you) — lifting the head away from the body, i.e., decapitation. The birds that ate the food in the baker's dream (v17) will eat the baker's flesh. The wordplay between the two interpretations using identical vocabulary with opposite valence is the narrator's demonstration of Joseph's interpretive precision — the same words apply to both, but the prepositions and referents differ fatally.</p>""",
    "20": """<p><strong>wayhî bayyôm haššĕlîšî yôm hullelet ʾet-parʿōh wayyaʿaś mišṭeh lĕḵōl-ʿăḇāḏāyw wayyiśśāʾ ʾet-rōʾš śar hammašqîm wĕʾet rōʾš śar hāʾōpîm bĕtôḵ ʿăḇāḏāyw</strong> — "On the third day — Pharaoh's birthday (<em>yôm hullelet</em>) — he gave a feast for all his officials and lifted the heads of the chief cupbearer and the chief baker in the presence of his officials." <em>Yôm hullelet ʾet-parʿōh</em> (the day of Pharaoh's birth) — the birthday feast is historically attested for Egyptian practice; the LXX and Josephus confirm this reading. The third day is both the dream-fulfillment day (as Joseph predicted) and the king's birthday — a day of royal clemency and judgment. Both men's "heads are lifted" simultaneously — the idiom fulfilled in its double meaning within a single verse.</p>""",
    "21": """<p><strong>wayyāšeb ʾet-śar hammašqîm ʿal-mašqēhû wayyittēn hakōs ʿal-kap parʿōh</strong> — "He restored the chief cupbearer to his position, so that he put the cup in Pharaoh's hand." The restoration is described in the exact vocabulary of the cupbearer's own dream (v11: "I put the cup in Pharaoh's hand"). The dream-vision and the fulfillment share the identical final image — cup in Pharaoh's hand. This exact correspondence confirms Joseph's interpretive credibility, which will matter in ch 41 when Pharaoh dreams.</p>""",
    "22": """<p><strong>wĕʾēt śar hāʾōpîm tālāh kaʾăšer pātar lāhem yôsēp</strong> — "But he hanged the chief baker, just as Joseph had said." <em>Tālāh</em> (H8518, to hang/impale) — the execution verb. The closing confirmation — <em>kaʾăšer pātar lāhem yôsēp</em> (just as Joseph had interpreted for them) — is the narrator's validation of Joseph's divine-interpretive authority. The fulfillment of both interpretations, one positive and one fatal, proves that Joseph's claims to divine interpretation were true. This double-fulfillment verification sets up the credibility transfer to Pharaoh's own dreams in ch 41.</p>""",
    "23": """<p><strong>wĕlōʾ-zāḵar śar-hammašqîm ʾet-yôsēp wayyiškāḥēhû</strong> — "Yet the chief cupbearer did not remember Joseph; he forgot him." The closing double-verb of forgetting — <em>lōʾ-zāḵar</em> (did not remember) + <em>wayyiškāḥēhû</em> (he forgot him) — is the narrative's most poignant moment. <em>Zāḵar</em> (H2142, to remember) is the covenant-memory verb: God "remembered" Noah (8:1), God "remembered" Rachel (30:22), God "remembered" Abraham when Lot was in danger (19:29); Israel is commanded to "remember" (Deut 5:15; 8:2). Human forgetting and divine remembering are the two poles of the covenant memory tradition. The cupbearer forgets; the reader is left with the knowledge that YHWH will remember (41:1: "after two full years, Pharaoh dreamed"). The chapter ends on human failure; the next chapter will open with divine timing.</p>"""
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_ORIGINAL)
    save_comm('mkt-original', 'genesis', existing)

    result = load_comm('mkt-original', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [38, 39, 40]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis total: {total_chs} chapters, {total_vv} verses with original data')
    print('Genesis 38-40 mkt-original written.')

if __name__ == '__main__':
    main()
